/**
 * AQL APPS - Inline Service Worker Fallback
 * Generates a service worker from a string to avoid 404s
 */

const SW_CODE = `
// AQL APPS - Inline Service Worker (v1.3.2)
self.addEventListener('install', (e) => self.skipWaiting());
self.addEventListener('activate', (e) => e.waitUntil(self.clients.claim()));

self.addEventListener('push', (event) => {
  let data = {
    title: 'AQL Vision',
    body: 'Nova notificação do sistema',
    icon: '/aql-engineering-logo.png',
    badge: '/aql-engineering-logo.png'
  };

  if (event.data) {
    try {
      const json = event.data.json();
      data = Object.assign({}, data, json);
    } catch (e) {
      data.body = event.data.text();
    }
  }

  const options = {
    body: data.body,
    icon: data.icon,
    badge: data.badge,
    vibrate: data.vibrate || [100, 50, 100],
    data: data.data || { url: '/demo' },
    actions: data.actions || [
      { action: 'open', title: 'Abrir App' },
      { action: 'close', title: 'Fechar' }
    ],
    tag: data.tag || 'aql-notification',
    renotify: true,
    requireInteraction: data.requireInteraction || false
  };

  event.waitUntil(
    self.registration.showNotification(data.title, options)
  );
});

self.addEventListener('notificationclick', (event) => {
  event.notification.close();
  const urlToOpen = (event.notification.data && event.notification.data.url) || '/';
  
  event.waitUntil(
    self.clients.matchAll({ type: 'window', includeUncontrolled: true })
      .then((clientList) => {
        for (const client of clientList) {
          if (client.url.includes(urlToOpen) && 'focus' in client) {
            return client.focus();
          }
        }
        if (self.clients.openWindow) {
          return self.clients.openWindow(urlToOpen);
        }
      })
  );
});
`;

export async function registerInlineServiceWorker(): Promise<ServiceWorkerRegistration> {
  // If we are in a protocol-restricted environment, this will throw
  try {
    const blob = new Blob([SW_CODE], { type: 'application/javascript' });
    const url = URL.createObjectURL(blob);
    const reg = await navigator.serviceWorker.register(url, { scope: '/' });
    return reg;
  } catch (blobError: any) {
    // If protocol is not supported, don't try data URI as it's usually also blocked
    if (blobError?.message?.includes('protocol') || blobError?.name === 'SecurityError') {
      throw new Error('Service Worker protocols (blob/data) are restricted in this environment');
    }
    
    // Try Data URI as extreme fallback
    try {
      const encoded = encodeURIComponent(SW_CODE);
      const dataUri = `data:application/javascript;charset=utf-8,${encoded}`;
      const reg = await navigator.serviceWorker.register(dataUri, { scope: '/' });
      return reg;
    } catch (dataError) {
      throw new Error('All inline registration methods failed');
    }
  }
}
